t;:210},&quot;szCs&quot;:{&quot;val&quot;:210},&quot;egRPrOpenType&quot;:{&quot;ligatures&quot;:{&quot;val&quot;:1}},&quot;rStyle&quot;:{},&quot;author&quot;:&quot;p.144115214525402658&quot;},&quot;mode&quot;:1,&quot;preventFormatTrackChanges&quot;:false},&quot;propertyType&quot;:&quot;RunProperty&quot;,&quot;builtinStyleName&quot;:&quot;&quot;},{&quot;operationType&quot;:&quot;InsertText&quot;,&quot;param&quot;:{&quot;text&quot;:&quot;\\r&quot;,&quot;range&quot;:{&quot;gcpBegin&quot;:485,&quot;len&quot;:0},&quot;preventTextTrackChanges&quot;:false},&quot;builtinStyleName&quot;:&quot;&quot;},{&quot;operationType&quot;:&quot;ModifyRunProp&quot;,&quot;param&quot;:{&quot;range&quot;:{&quot;gcpBegin&quot;:485,&quot;len&quot;:1},&quot;property&quot;:{&quot;rFonts&quot;:{&quot;ascii&quot;:&quot;微软雅黑&quot;,&quot;hAnsi&quot;:&quot;微软雅黑&quot;,&quot;eastAsia&quot;:&quot;微软雅黑&quot;,&quot;cs&quot;:&quot;Segoe UI&quot;},&quot;color&quot;:{&quot;val&quot;:&quot;0F1115&quot;},&quot;kern&quot;:{&quot;val&quot;:0},&quot;sz&quot;:{&quot;val&quot;:210},&quot;szCs&quot;:{&quot;val&quot;:210},&quot;isPlaceholder&quot;:true,&quot;author&quot;:&quot;p.144115214525402658&quot;,&quot;rStyle&quot;:{}},&quot;mode&quot;:1,&quot;preventFormatTrackChanges&quot;:false},&quot;propertyType&quot;:&quot;RunProperty&quot;,&quot;builtinStyleName&quot;:&quot;&quot;},{&quot;operationType&quot;:&quot;ModifyParagraphProp&quot;,&quot;param&quot;:{&quot;range&quot;:{&quot;gcpBegin&quot;:485,&quot;len&quot;:1},&quot;property&quot;:{&quot;widowControl&quot;:{&quot;val&quot;:true},&quot;shd&quot;:{&quot;val&quot;:2,&quot;color&quot;:&quot;STHexColorAuto_auto&quot;,&quot;fill&quot;:&quot;FFFFFF&quot;},&quot;spacing&quot;:{&quot;before&quot;:240,&quot;after&quot;:240,&quot;line&quot;:400,&quot;lineRule&quot;:2},&quot;ind&quot;:{},&quot;numPr&quot;:{},&quot;pStyle&quot;:{}},&quot;mode&quot;:1,&quot;preventFormatTrackChanges&quot;:false},&quot;propertyType&quot;:&quot;ParagraphProperty&quot;,&quot;builtinStyleName&quot;:&quot;&quot;}],&quot;subStory&quot;:[],&quot;srcGlobalPadId&quot;:&quot;300000000$CLJmOAlSKHnL&quot;,&quot;copyStart&quot;:34}" data-version="3.0.0" inner_data_type="webData" data-hash="4b1dfa0c99d0d9f863f0f55480788e15" style="color: rgb(0, 0, 0); font-size: medium;"></div><div class="document" style="color: rgb(0, 0, 0); font-size: medium;"><div class="section"><p class="paragraph text-align-type-center" style="margin: 0pt; text-align: center; font-family: 等线; font-size: 12pt; line-height: 20pt;"><span data-font-family="微软雅黑" style="font-size: 16pt; font-family: 微软雅黑; font-weight: bold; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">你的手机，是数字时代的“地契”还是“卖身契”？</span><span lang="EN-US" style="font-size: 16pt; font-family: 微软雅黑; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;"><o:p></o:p></span></p><p class="paragraph text-align-type-justify" style="margin: 0pt; text-align: justify; font-family: 等线; font-size: 12pt; line-height: 20pt;"><span lang="EN-US" style="font-size: 10.5pt; font-family: 微软雅黑; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">&nbsp;</span></p><p class="paragraph text-align-type-justify" style="margin: 0pt; text-align: justify; font-family: 等线; font-size: 12pt; line-height: 20pt;"><span data-font-family="微软雅黑" style="font-size: 10.5pt; font-family: 微软雅黑; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">在2025年世界人工智能大会的演讲台上，被誉为“AI教父”的杰弗里·辛顿，这位用毕生精力赋予机器智能的奠基人，说出了最令人心寒的判词：“</span><span data-font-family="微软雅黑" style="font-size: 10.5pt; font-family: 微软雅黑; font-weight: bold; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">我花了一生让AI变得智能，现在却要花余生让它变得友善。</span><span data-font-family="微软雅黑" style="font-size: 10.5pt; font-family: 微软雅黑; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">” 他反复追问的并非技术细节，而是一个文明的病症：“</span><span data-font-family="微软雅黑" style="font-size: 10.5pt; font-family: 微软雅黑; font-weight: bold; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">为什么我们不愤怒？为什么不抗议？</span><span data-font-family="微软雅黑" style="font-size: 10.5pt; font-family: 微软雅黑; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">”</span><span lang="EN-US" style="font-size: 10.5pt; font-family: 微软雅黑; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;"><o:p></o:p></span></p><p class="paragraph text-align-type-justify" style="margin: 12pt 0pt; text-align: justify; font-family: 等线; font-size: 12pt; line-height: 20pt;"><span data-font-family="微软雅黑" style="font-size: 10.5pt; font-family: 微软雅黑; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">辛顿的困惑揭示了一个比AI失控概率更可怕的现实：</span><span data-font-family="微软雅黑" style="font-size: 10.5pt; font-family: 微软雅黑; font-weight: bold; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">认知的麻痹</span><span data-font-family="微软雅黑" style="font-size: 10.5pt; font-family: 微软雅黑; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">。当马斯克在内部会议上警告AI毁灭人类的概率“在20%左右”时，当历史学家赫拉利描绘AI正在接管人类“灵魂解释权”的恐怖图景时，绝大多数人仍在为5年后是否会被ChatGPT取代工作而焦虑。这不是公众的愚钝，而是</span><span data-font-family="微软雅黑" style="font-size: 10.5pt; font-family: 微软雅黑; font-weight: bold; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">系统性的信息不对称</span><span data-font-family="微软雅黑" style="font-size: 10.5pt; font-family: 微软雅黑; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">所制造的认知深渊。</span><span lang="EN-US" style="font-size: 10.5pt; font-family: 微软雅黑; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;"><o:p></o:p></span></p><p class="paragraph text-align-type-justify" style="margin: 12pt 0pt; text-align: justify; font-family: 等线; font-size: 12pt; line-height: 20pt;"><span data-font-family="微软雅黑" style="font-size: 10.5pt; font-family: 微软雅黑; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">前沿的精英们在晚宴上争论篝火是否会熄灭，而大众甚至不知道自己正坐在柴堆之上。这堵无形的认知高墙，正是“灰马骑士”——科技反噬——得以悄然逼近的第一道，也是最牢固的防线。本文旨在发起一场针对这堵高墙的</span><span data-font-family="微软雅黑" style="font-size: 10.5pt; font-family: 微软雅黑; font-weight: bold; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">认知总攻</span><span data-font-family="微软雅黑" style="font-size: 10.5pt; font-family: 微软雅黑; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">，并指出，破墙的工具不在别处，就在我们每个人手中的智能手机里。这不是另一份乌托邦蓝图，而是一份对</span><span data-font-family="微软雅黑" style="font-size: 10.5pt; font-family: 微软雅黑; font-weight: bold; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">早已存在却视而不见的现实</span><span data-font-family="微软雅黑" style="font-size: 10.5pt; font-family: 微软雅黑; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;">的承认书。</span><span lang="EN-US" style="font-size: 10.5pt; font-family: 微软雅黑; color: rgb(15, 17, 21); letter-spacing: 0pt; vertical-align: baseline;"><o:p></o:p></span></p></div></div>	2026-03-22 11:09:59.056896+00	致全球科学家的一封公开信；				
\.


